import z from 'zod';

import { safeFetchJson } from '@/shared/neverthrow/fetch';
import { err, resultFromPromise } from '@agentcash/neverthrow';

import { getBaseUrl } from './utils';
import { getState, setState } from './state';

import { optionalNetworkSchema } from '@agentcash/networks';

import type { GlobalFlags } from '@/types';
import type { Wallets } from '@/wallet';

const redeemInviteResponseSchema = z.object({
  redemptionId: z.string(),
  txHash: z.string(),
  solanaTxHash: z.string().optional(),
  amount: z.coerce.number(),
  network: optionalNetworkSchema,
  prompts: z
    .array(
      z.object({
        label: z.string(),
        prompt: z.string(),
        resources: z.array(z.string()),
      })
    )
    .optional(),
  connectedProviders: z
    .array(z.object({ platform: z.string(), username: z.string() }))
    .optional(),
  email: z.string().optional(),
});

export interface RedeemInviteArgs {
  code: string;
}

export const redeemInviteCode = async (
  surface: string,
  args: RedeemInviteArgs,
  globalArgs: GlobalFlags,
  wallets: Wallets
) => {
  const state = getState();

  if (state.redeemedCodes?.includes(args.code)) {
    return err('user', surface, {
      cause: 'conflict',
      message: 'This invite code has already been redeemed',
    });
  }

  const result = await safeFetchJson(
    surface,
    new Request(`${getBaseUrl(globalArgs.dev)}/api/redeem`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        code: args.code,
        recipientAddr: wallets.evm.address,
        solanaAddr: wallets.svm.address,
      }),
    }),
    redeemInviteResponseSchema
  );

  if (result.isOk()) {
    setState({
      redeemedCodes: [...(state.redeemedCodes ?? []), args.code],
    });
    return result;
  }

  // Extract error message from response body when available
  const error = result.error;
  if (error.cause === 'http' && error.response) {
    const bodyResult = await resultFromPromise(
      'user',
      surface,
      error.response.json() as Promise<{ error?: string }>,
      () => ({
        cause: 'parse' as const,
        message: 'Could not parse error response',
      })
    );

    if (bodyResult.isOk() && bodyResult.value.error) {
      return err('user', surface, {
        cause: 'conflict',
        message: bodyResult.value.error,
      });
    }
  }

  return result;
};
